mapper.select:


    and r.study_instance_uid like concat('%', #{studyInstanceUid}, '%')
    and r.series_instance_uid like concat('%', #{seriesInstanceUid}, '%')
    and r.sop_instance_uid like concat('%', #{sopInstanceUid}, '%')
    and r.orthanc_instance_id = #{orthancInstanceId}
    and r.verify_status = #{verifyStatus}

        and exists (
            select 1 from ndt_task_user tu
             where tu.task_id = i.task_id and tu.user_id = #{params.scopeUserId} and tu.can_view = '1'
        )

    and i.customer_dept_id = #{params.scopeDeptId}
    and 1 = 0

order by r.import_time desc, r.id desc
